INSERT INTO `doctors` VALUES (14,1,1,'李主任','妇产科主任','各类妇科常见病、多发病及疑难病症诊治，包括阴道炎、盆腔炎、月经不调、子宫肌瘤、卵巢囊肿等；精通孕前备孕指导、早中晚孕期规范产检、高危妊娠监护、难产处理及剖宫产、妇科常规手术。待人亲切有耐心，诊疗细致严谨，专注女性全生命周期健康，为育龄女性及孕产妇提供专业、安心、人性化的医疗服务。','../uploads/avatar_6a042751c09e5.jpg','从事妇产科临床工作二十余年，临床经验扎实丰富。','auto',20,15,0.00,'2026-04-01 16:30:38','2026-05-24 01:19:33','妇产科'),(13,1,1,'闻主任','妇产科主任','常规产检、孕期营养指导、顺产助产及妇科常见疾病诊治，对早孕安胎、月经调理、青春期及更年期女性健康管理经验丰富。性格温和耐心，善于倾听患者诉求，诊疗方案个性化、接地气，兼顾医疗专业性与服务温度，深受宝妈及女性患者信赖。','../uploads/avatar_6a04275c1fe87.jpg','青年骨干妇产科医师，毕业于重点医学院校，长期从事妇产科临床、保健及科普工作。','auto',20,15,0.00,'2026-05-13 07:02:47','2026-05-13 10:51:47','妇产科'),(16,1,1,'陶虹','妇产科主任','孕前优生咨询、孕期系统产检、妊娠期高血压、糖尿病等高危妊娠管理，熟练处理顺产、难产助产及剖宫产手术。同时擅长妇科炎症、内分泌失调、备孕不孕调理及产后康复指导。秉持严谨行医作风，沟通耐心细致，注重个体化诊疗方案，用心守护母婴安全与女性身心健康。','../uploads/avatar_6a3a40fd4ad7a.png','深耕妇产科临床一线多年，主攻围产医学与孕期保健。','auto',20,15,0.00,'2026-04-02 06:15:48','2026-06-23 08:17:01','妇产科'),(17,1,1,'王云','妇科主任','妇科炎症，月经不调，私密整形，阴道紧缩等，微创诊疗方式，诊疗理念温和保守，兼顾疗效与隐私保护。对待患者认真负责、亲和力强，为广大女性提供专业私密、贴心靠谱的专属健康诊疗服务。','../uploads/avatar_6a3a40a1e8f6e.png','专注妇产科临床诊疗工作多年，理论功底深厚，实操经验丰富。擅长妇科炎症、宫颈疾病、月经紊乱、私密整形、不孕不育诊治；主攻妇科疾病、私密整形修复、产后形体与子宫恢复。','manual',20,15,0.00,'2026-04-02 14:01:12','2026-06-23 08:16:02','妇产科');
/*!40000 ALTER TABLE `doctors` ENABLE KEYS */;
UNLOCK TABLES;

